// Preprocess incoming startup documents
const body = $input.first().json.body || $input.first().json;
const documents = body.documents || [];
const companyName = body.companyName || 'Unknown Company';
const companyId = body.companyId || 'unknown';

// Combine all document text
const combinedText = documents.map(d => {
  const label = d.type ? `[${d.type.toUpperCase()}]` : '[DOC]';
  return `${label}\n${d.content || d.text || JSON.stringify(d)}`;
}).join('\n\n---\n\n');

return [{
  json: {
    companyName,
    companyId,
    documents,
    combinedText,
    docCount: documents.length,
    timestamp: new Date().toISOString()
  }
}];

const body = $input.first().json.body || $input.first().json;
const documents = body.documents || [];
const companyName = body.companyName || 'Unknown Company';
const companyId = body.companyId || 'unknown';

const combinedText = documents.length > 0
  ? documents.map(d => {
      const label = d.type ? `[${d.type.toUpperCase()}]` : '[DOC]';
      return `${label}\n${d.content || d.text || JSON.stringify(d)}`;
    }).join('\n\n---\n\n')
  : (body.combinedText || '');

return [{
  json: {
    companyName,
    companyId,
    documents,
    combinedText,
    docCount: documents.length,
    timestamp: new Date().toISOString()
  }
}];

// Format merged specialist outputs for Audit Agent
const items = $input.all();
const companyName = items[0]?.json?.companyName || 'Unknown Company';
const agentNames = ['KPI & Financials', 'Traction & Team', 'Market Map', 'Red Flags'];
const output = {};
items.forEach((item, i) => {
  output[agentNames[i] || `Agent ${i + 1}`] = item.json;
});
return [{
  json: {
    companyName,
    output: JSON.stringify(output, null, 2)
  }
}];
